def perceive(data):
    mem = []
    t = 0
    for line in str(data).splitlines():
        line = line.strip()
        if not line:
            continue
        if ':' in line:
            cue, value = line.split(':', 1)
            cue, value = cue.strip(), value.strip()
        else:
            cue = value = line
        mem.append({"cue": cue, "value": value, "t": t})
        t += 1
    return {"memory": mem, "size": len(mem), "clock": len(mem)}
